/* /digests/:id Summarize with Claude form. Same loading-state pattern
 * as triage-form.js — Summarizer::Claude.summarize on a full digest is
 * a 5-15s synchronous API call, and without feedback the button looks
 * dead. The form also opts out of Turbo (data-turbo="false") so the
 * browser does classic full-page navigation rather than a silent
 * background fetch.
 *
 * On submit we disable the button + swap the label. We do NOT
 * preventDefault — the form still submits normally and the existing
 * route renders the result page with a "Summary generated by …" notice. */
(function () {
  'use strict';

  var forms = document.querySelectorAll('form.js-digest-summarize');
  if (!forms.length) return;

  forms.forEach(function (form) {
    form.addEventListener('submit', function () {
      var btn = form.querySelector('button[type="submit"]');
      if (!btn || btn.disabled) return;
      btn.dataset.originalText = btn.textContent.trim();
      btn.disabled = true;
      btn.classList.add('is-loading');
      btn.textContent = 'Summarizing… (5–15s)';
    });
  });
})();
